/**
 * @event 
 * @name sbm_RetrieveWorkResult_submitdone 
 * @description Response Status 코드 값이 정상 일 경우 동작.
 */
scwin.sbm_RetrieveWorkResult_submitdone = function (e) {
  const rowCnt = ds_RetrieveWorkResult.getRowCount();
  if (rowCnt == 0) {
    $c.gus.cfAlertMsg($p, '[중기별 기간작업 실적 정보] ' + MSG_CM_ERR_003);
  }
  ;
  const footerRowCnt = 1;
  const subTotalCnt = gr_RetrieveWorkResult.getSubtotalRowList().length;
  totalRows.setValue(rowCnt + subTotalCnt + footerRowCnt);
};

